import React, { useState } from "react";
import "./Sidebar.css";

const Sidebar = () => {
    const [active, setActive] = useState("");

    const menuGroups = [
        {
            title: "SİPARİŞ İŞLEMLERİ",
            items: ["Sipariş Oluştur", "Teslim Noktaları"],
        },
        {
            title: "GELİR & GİDER",
            items: ["Gelir Ekleme", "Gider Ekleme", "Eskalasyon Hesabı"],
        },
        {
            title: "RAPORLAR",
            items: ["Tedarik Analiz"],
        },
    ];

    const handleClick = (label) => {
        setActive(label);
        // Gerekirse yönlendirme yapılabilir
        console.log("Tıklanan menü:", label);
    };

    return (
        <aside className="sidebar">
            {menuGroups.map((group) => (
                <div key={group.title} className="menu-group">
                    <div className="menu-title">{group.title}</div>
                    <ul>
                        {group.items.map((item) => (
                            <li
                                key={item}
                                className={active === item ? "active" : ""}
                                onClick={() => handleClick(item)}
                            >
                                {item}
                            </li>
                        ))}
                    </ul>
                </div>
            ))}
        </aside>
    );
};

export default Sidebar;
